// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  // Get weather icon/emoji based on condition
  const getWeatherIcon = useCallback((condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloud')) return '☁️';
    if (conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
    if (conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
    return '🌤️'; // default
  }, []);

  return {
    getWeatherIcon
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="md" padding={16}>
      <Card shadow="md" padding={24} radius="lg">
        {/* Header with city name */}
        <Stack gap={4} align="center" justify="center">
          <Heading level={2} align="center">
            {props.city}
          </Heading>
        </Stack>

        <Divider margin={16} />

        {/* Current weather section */}
        <Stack gap={16}>
          {/* Temperature and condition display */}
          <Stack gap={12} align="center" justify="center">
            {/* Weather icon */}
            <Box style={{ fontSize: '64px', lineHeight: '1' }}>
              {state.getWeatherIcon(props.condition)}
            </Box>

            {/* Temperature - large and prominent */}
            <Heading level={1} align="center" style={{
              fontSize: 'var(--ggui-font-size-4xl, 36px)',
              fontWeight: 'var(--ggui-font-weight-bold, 700)',
              margin: 0
            }}>
              {Math.round(props.temperature)}°{props.unit}
            </Heading>

            {/* Weather condition */}
            <Text variant="bodyLarge" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {props.condition}
            </Text>
          </Stack>

          <Divider margin={12} />

          {/* Weather details grid */}
          <Stack direction="horizontal" gap={16} align="center" justify="center">
            {/* Humidity */}
            <Box style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              gap: 'var(--ggui-spacing-2, 8px)'
            }}>
              <Icon name="droplets" size={20} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="bodySmall">Humidity</Text>
              <Text variant="label" weight="bold">{props.humidity}%</Text>
            </Box>

            {/* Wind Speed */}
            <Box style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              gap: 'var(--ggui-spacing-2, 8px)'
            }}>
              <Icon name="wind" size={20} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="bodySmall">Wind Speed</Text>
              <Text variant="label" weight="bold">{props.windSpeed} km/h</Text>
            </Box>
          </Stack>
        </Stack>

        <Divider margin={16} />

        {/* 5-day forecast */}
        <Stack gap={8}>
          <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            5-Day Forecast
          </Text>
          <Stack direction="horizontal" gap={8} align="center" wrap>
            {props.forecast && props.forecast.length > 0 ? (
              props.forecast.map((day, index) => (
                <Card key={index} shadow="sm" padding={12} radius="md" style={{
                  flex: '0 1 auto',
                  minWidth: '100px',
                  textAlign: 'center'
                }}>
                  {/* Day name */}
                  <Text variant="label" weight="medium" align="center">
                    {day.day || `Day ${index + 1}`}
                  </Text>

                  {/* Weather icon */}
                  <Box style={{
                    fontSize: '28px',
                    lineHeight: '1',
                    margin: 'var(--ggui-spacing-2, 8px) 0'
                  }}>
                    {day.icon || state.getWeatherIcon(day.day || '')}
                  </Box>

                  {/* High/Low temps */}
                  <Stack gap={2} align="center" justify="center">
                    <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      {day.high !== undefined ? `${Math.round(day.high)}°${props.unit}` : '-'}
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {day.low !== undefined ? `${Math.round(day.low)}°${props.unit}` : '-'}
                    </Text>
                  </Stack>
                </Card>
              ))
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No forecast data available
              </Text>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for multi-step form
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation functions
  const isValidEmail = useCallback((value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  const isNameValid = useCallback(() => name.trim().length > 0, [name]);
  const isEmailValid = useCallback(() => isValidEmail(email), [email, isValidEmail]);

  const canProceedStep1 = useCallback(() => {
    return isNameValid() && isEmailValid();
  }, [isNameValid, isEmailValid]);

  const canProceedStep2 = useCallback(() => {
    return satisfaction !== '';
  }, [satisfaction]);

  const canProceedStep3 = useCallback(() => {
    return true; // Features are optional
  }, []);

  const handleFeatureToggle = useCallback((feature: string) => {
    setFeatures(prev =>
      prev.includes(feature)
        ? prev.filter(f => f !== feature)
        : [...prev, feature]
    );
  }, []);

  const handleBack = useCallback(() => {
    setCurrentStep(prev => Math.max(prev - 1, 1));
  }, []);

  const handleNext = useCallback(() => {
    if (currentStep === 1 && canProceedStep1()) {
      setCurrentStep(2);
    } else if (currentStep === 2 && canProceedStep2()) {
      setCurrentStep(3);
    } else if (currentStep === 3 && canProceedStep3()) {
      setCurrentStep(4);
    } else if (currentStep === 4) {
      setCurrentStep(5);
    }
  }, [currentStep, canProceedStep1, canProceedStep2, canProceedStep3]);

  const handleSubmit = useCallback(() => {
    const satisfactionIndex = parseInt(satisfaction, 10);
    submit({
      name,
      email,
      satisfaction: satisfactionIndex,
      features,
      comments
    });
  }, [name, email, satisfaction, features, comments, submit]);

  const nameError = name.trim().length === 0 && name !== '' ? 'Name is required' : '';
  const emailError = email !== '' && !isValidEmail(email) ? 'Please enter a valid email address' : (email === '' ? 'Email is required' : '');

  return { submit, currentStep, setCurrentStep, name, setName, email, setEmail, satisfaction, setSatisfaction, features, handleFeatureToggle, comments, setComments, nameError, emailError, canProceedStep1, canProceedStep2, canProceedStep3, handleBack, handleNext, handleSubmit, isValidEmail };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* Progress Bar */}
        <Box>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
            Step {state.currentStep} of 4
          </Text>
          <Spacer size={8} />
          <Progress
            value={state.currentStep}
            max={4}
            variant="default"
            size="md"
            aria-label={`Step ${state.currentStep} of 4`}
          />
        </Box>

        {/* Step 1: Name and Email */}
        {state.currentStep === 1 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Contact Information</Heading>
              <Input
                label="Name"
                value={state.name}
                onChange={state.setName}
                placeholder="Enter your name"
                required
                error={state.nameError}
              />
              <Input
                label="Email"
                type="email"
                value={state.email}
                onChange={state.setEmail}
                placeholder="Enter your email"
                required
                error={state.emailError}
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {state.currentStep === 2 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={state.satisfaction}
                onChange={state.setSatisfaction}
                 options={props.satisfactionLabels?.map((label, index) => ({
                   value: String(index + 1),
                   label: label
                 })) || []}
                direction="vertical"
                aria-labelledby="satisfaction-label"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {state.currentStep === 3 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Which features interest you?</Heading>
              <Stack gap={12}>
                {props.featureOptions?.map(feature => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={state.features.includes(feature)}
                    onChange={() => state.handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Card>
          )}
        {/* Step 4: Comments */}
        {state.currentStep === 4 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Additional Comments</Heading>
              <Stack gap={8}>
                <TextArea
                  label="Comments"
                  value={state.comments}
                  onChange={state.setComments}
                  placeholder="Share your thoughts (optional)"
                  maxLength={500}
                  showCount
                  rows={6}
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" aria-live="polite">
                  {state.comments.length}/500 characters
                </Text>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 5: Final Review */}
        {state.currentStep === 5 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Heading level={3}>Review Your Answers</Heading>
              <Divider />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                <Text>{state.name}</Text>
              </Box>
              <Divider />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                <Text>{state.email}</Text>
              </Box>
              <Divider />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
                <Text>{props.satisfactionLabels?.[parseInt(state.satisfaction, 10) - 1] || 'N/A'}</Text>
               </Box>
               <Divider />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Interested Features</Text>
                 <Stack gap={4} direction="horizontal">
                  {state.features.map(feature => (
                    <Badge key={feature} variant="primary" size="sm">{feature}</Badge>
                  ))}
                </Stack>
              </Box>
              <Divider />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                <Text>{state.comments || '(No comments provided)'}</Text>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Stack direction="horizontal" gap={12} justify="between">
          <Button
            variant="ghost"
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
            aria-disabled={state.currentStep === 1}
          >
            Back
          </Button>
          {state.currentStep < 5 ? (
            <Button
              variant="primary"
              onClick={state.handleNext}
              disabled={
                (state.currentStep === 1 && !state.canProceedStep1()) ||
                (state.currentStep === 2 && !state.canProceedStep2()) ||
                (state.currentStep === 3 && !state.canProceedStep3())
              }
              aria-disabled={
                (state.currentStep === 1 && !state.canProceedStep1()) ||
                (state.currentStep === 2 && !state.canProceedStep2()) ||
                (state.currentStep === 3 && !state.canProceedStep3())
              }
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={state.handleSubmit}
            >
              Submit
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state
  const [tasks, setTasks] = useState(props.tasks);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [showAddForm, setShowAddForm] = useState<string | null>(null);

  // Sync tasks from props
  React.useEffect(() => {
    setTasks(props.tasks);
  }, [props.tasks]);

  // Listen for real-time task updates from stream
  React.useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (task?.id) {
        if (action === 'delete') {
          setTasks((prev) => prev.filter((t) => t.id !== task.id));
        } else {
          setTasks((prev) => {
            const idx = prev.findIndex((t) => t.id === task.id);
            if (idx >= 0) {
              const updated = [...prev];
              updated[idx] = { ...updated[idx], ...task };
              return updated;
            } else {
              return [...prev, task];
            }
          });
        }
      }
    }
  }, [taskChanged.latest]);

  // Listen for ggui:agent-data events (real-time sync from agent)
  React.useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      if (data?.type === 'taskChanged' && data?.payload) {
        const { action, task } = data.payload;
        if (task?.id) {
          if (action === 'delete') {
            setTasks((prev) => prev.filter((t) => t.id !== task.id));
          } else {
            setTasks((prev) => {
              const idx = prev.findIndex((t) => t.id === task.id);
              if (idx >= 0) {
                const updated = [...prev];
                updated[idx] = { ...updated[idx], ...task };
                return updated;
              } else {
                return [...prev, task];
              }
            });
          }
        }
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  // Compute tasks per column
  const tasksByColumn = useCallback(() => {
    const result: Record<string, typeof tasks> = {};
    props.columns.forEach((col) => {
      result[col.id || ''] = tasks.filter((t) => t.column === col.id);
    });
    return result;
  }, [tasks, props.columns]);

  // Count completed tasks (tasks in 'done' column)
  const completedCount = useCallback(() => {
    return tasks.filter((t) => t.column === 'done').length;
  }, [tasks]);

  // Create new task
  const handleCreateTask = useCallback((columnId: string) => {
    if (newTaskTitle.trim()) {
      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
        assignee: '',
        dueDate: '',
      };
      setTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setShowAddForm(null);
    }
  }, [newTaskTitle, newTaskPriority, taskUpdate]);

  // Edit task title
  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    if (newTitle.trim()) {
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
      );
      taskUpdate({ action: 'edit', taskId, data: { column: '' } });
      setEditingTaskId(null);
      setEditingTitle('');
    }
  }, [taskUpdate]);

  // Move task to another column
  const handleMoveTask = useCallback((taskId: string, targetColumn: string) => {
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t))
    );
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  }, [taskUpdate]);

  return {
    tasks,
    editingTaskId,
    editingTitle,
    setEditingTaskId,
    setEditingTitle,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    showAddForm,
    setShowAddForm,
    tasksByColumn,
    completedCount,
    handleCreateTask,
    handleEditTask,
    handleMoveTask,
    taskUpdate,
    taskChanged,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const getPriorityColor = (priority: string | undefined) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  const tasksByCol = state.tasksByColumn();
  const completed = state.completedCount();
  const total = state.tasks.length;

  return (
    <Stack gap={24}>
      {/* Summary bar at top */}
      <Box paddingX={16} paddingY={12} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius={8}>
        <Stack direction="horizontal" align="center" justify="between">
          <Text variant="body" color="var(--ggui-color-primary-900, #0c4a6e)">
            Total Tasks: <strong>{total}</strong> • Completed: <strong>{completed}</strong>
          </Text>
        </Stack>
      </Box>

      {/* Kanban board */}
      <Stack direction="horizontal" gap={20} wrap={false}>
        {props.columns.map((column) => {
          const columnTasks = tasksByCol[column.id || ''] || [];
          const showForm = state.showAddForm === column.id;

          return (
            <Card key={column.id} shadow="md" padding={16} radius="lg" style={{ flex: '1 1 350px', minHeight: '600px', display: 'flex', flexDirection: 'column' }}>
              {/* Column header */}
              <Stack gap={12} justify="start">
                <Stack direction="horizontal" align="center" justify="between">
                  <Stack direction="horizontal" align="center" gap={8}>
                    <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                      {column.name}
                    </Heading>
                    <Badge variant="default" size="sm">
                      {columnTasks.length}
                    </Badge>
                  </Stack>
                </Stack>
                <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
              </Stack>

              {/* Task list */}
              <Stack gap={12} style={{ flex: '1', overflowY: 'auto', marginBottom: 'var(--ggui-spacing-2, 8px)' }}>
                {columnTasks.map((task) => (
                  <Card
                    key={task.id}
                    shadow="sm"
                    padding={12}
                    radius="md"
                    border={true}
                    style={{ backgroundColor: 'var(--ggui-color-surface, #fafafa)' }}
                  >
                    <Stack gap={8}>
                      {/* Task title */}
                      <div
                        style={{
                          display: state.editingTaskId === task.id ? 'none' : 'block',
                        }}
                      >
                        <Stack direction="horizontal" align="start" gap={8}>
                          <Text
                            variant="body"
                            size="sm"
                            style={{ flex: 1, wordBreak: 'break-word' }}
                            color="var(--ggui-color-onSurface, #18181b)"
                          >
                            {task.title}
                          </Text>
                          <Button
