interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by name or symbol (case-insensitive)
  const filteredElements = useMemo(() => {
    const elements = props.elements ?? [];
    if (!searchQuery.trim()) return elements;
    const query = searchQuery.toLowerCase();
    return elements.filter(el =>
      el.name?.toLowerCase().includes(query) ||
      el.symbol?.toLowerCase().includes(query)
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set<string>();
    (props.elements ?? []).forEach(el => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  // Map categories to colors (using CSS variables only, no hex fallbacks)
  const categoryColors: Record<string, string> = {
    'alkali-metal': 'var(--ggui-color-warning-100)',
    'alkaline-earth-metal': 'var(--ggui-color-info-100)',
    'transition-metal': 'var(--ggui-color-primary-100)',
    'lanthanide': 'var(--ggui-color-success-100)',
    'actinide': 'var(--ggui-color-error-100)',
    'nonmetal': 'var(--ggui-color-primary-50)',
    'halogen': 'var(--ggui-color-warning-50)',
    'noble-gas': 'var(--ggui-color-success-50)',
    'semimetal': 'var(--ggui-color-primary-200)',
    'other': 'var(--ggui-color-outline)',
  };

  const getCategoryColor = useCallback((category?: string) => {
    if (!category) return 'var(--ggui-color-surfaceVariant)'
    // Normalize hyphens for lookup
    const normalized = category.toLowerCase().replace(/\s+/g, '-');
    return categoryColors[normalized] || 'var(--ggui-color-surfaceVariant)';
  }, [categoryColors]);

  const handleElementClick = useCallback((element: typeof props.elements[0]) => {
    setSelectedElement(element);
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
    getCategoryColor,
    handleElementClick,
  };
}

