/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State for messages and typing indicator
  const [messages, setMessages] = useState(props.messages || []);
  const [inputText, setInputText] = useState('');
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom on new messages
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  // Listen for ggui:agent-data events from stream
  React.useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent;
      const { type, data } = customEvent.detail || {};

      if (type === 'message' && data) {
        setMessages(prev => [...prev, data]);
        scrollToBottom();
      } else if (type === 'typing' && data) {
        setTypingUser(data.active ? data.sender || null : null);
      }
    };

    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, [scrollToBottom]);

  // Handle incoming messages from stream
  React.useEffect(() => {
    if (message.latest) {
      setMessages(prev => [...prev, message.latest]);
      scrollToBottom();
    }
  }, [message.latest, scrollToBottom]);

  // Handle typing indicator from stream
  React.useEffect(() => {
    if (typing.latest) {
      setTypingUser(typing.latest.active ? typing.latest.sender || null : null);
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputText.trim()) {
      sendMessage({ text: inputText, timestamp: new Date().toISOString() });
      setMessages(prev => [...prev, { sender: props.currentUser, text: inputText, timestamp: new Date().toISOString() }]);
      setInputText('');
      scrollToBottom();
    }
  }, [inputText, sendMessage, props.currentUser, scrollToBottom]);

  // Handle Enter key
  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  return { sendMessage, message, typing, messages, inputText, setInputText, handleSendMessage, handleKeyDown, typingUser, messagesEndRef, scrollToBottom };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="md" padding={0}>
      <Card shadow="md" padding={0} radius="lg" style={{ display: 'flex', flexDirection: 'column', height: '100vh', maxHeight: '600px' }}>
        {/* Header */}
        <Box paddingX={16} paddingY={12} borderRadius={0} style={{ borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
          <Stack direction="horizontal" justify="between" align="center" gap={12}>
            <Stack direction="horizontal" align="center" gap={8}>
              <Heading level={4} style={{ margin: 0 }}>{props.title}</Heading>
            </Stack>
            <Stack direction="horizontal" align="center" gap={8}>
              <Badge variant="primary" size="sm">{props.participantCount} participants</Badge>
              {state.typingUser && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{state.typingUser} is typing...</Text>}
            </Stack>
          </Stack>
        </Box>

        {/* Messages List */}
        <Box paddingX={16} paddingY={12} borderRadius={0} style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '8px' }}>
          {state.messages.length === 0 ? (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center" style={{ marginTop: '24px' }}>No messages yet</Text>
          ) : (
            (state.messages || []).map((msg, idx) => {
              const isCurrentUser = msg.sender === props.currentUser;
              const showSender = idx === 0 || state.messages[idx - 1]?.sender !== msg.sender;
              return (
                <Box key={idx} style={{ display: 'flex', flexDirection: isCurrentUser ? 'row-reverse' : 'row', justifyContent: isCurrentUser ? 'flex-end' : 'flex-start', alignItems: 'flex-end', gap: '8px' }}>
                  {!isCurrentUser && <Avatar name={msg.sender || 'Unknown'} size="sm" />}
                  <Stack direction="vertical" gap={2} align={isCurrentUser ? 'end' : 'start'} style={{ maxWidth: '60%' }}>
                    {showSender && !isCurrentUser && <Text variant="label" style={{ marginBottom: '4px' }}>{msg.sender}</Text>}
                    <Box padding={12} borderRadius={8} background={isCurrentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'} style={{ wordWrap: 'break-word' }}>
                      <Text variant="body" color={isCurrentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}>{msg.text}</Text>
                    </Box>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ marginTop: '2px', fontSize: '11px' }}>{msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}</Text>
                  </Stack>
                </Box>
              );
            })
          )}
          <div ref={state.messagesEndRef} />
        </Box>

        {/* Input Area */}
        <Box paddingX={16} paddingY={12} borderRadius={0} style={{ borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
          <Stack direction="horizontal" gap={8} align="end">
            <Input
              label=""
              placeholder="Type a message..."
              value={state.inputText}
              onChange={state.setInputText}
              onKeyDown={state.handleKeyDown}
              style={{ flex: 1 }}
            />
            <Button variant="primary" onClick={state.handleSendMessage} disabled={!state.inputText.trim()}>Send</Button>
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}

