// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for stock data and highlight animation
  const [displayStocks, setDisplayStocks] = useState(props.stocks || []);
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [streamError, setStreamError] = useState<string | null>(null);
  // Merge price updates into display stocks and track which updated
  const handlePriceUpdate = useCallback(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
       setDisplayStocks((prevStocks) => {
         const updated = (prevStocks || []).map((stock) => {
          if (stock.symbol === update.symbol) {
            return {
              ...stock,
              price: update.price ?? stock.price,
              change: update.change ?? stock.change,
              changePercent: update.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
        return updated;
      });

      // Highlight the updated stock symbol
      if (update.symbol) {
        setHighlightedSymbols((prev) => new Set(prev).add(update.symbol));
        setLastUpdated(new Date());
        // Remove highlight after 800ms
        setTimeout(() => {
          setHighlightedSymbols((prev) => {
            const next = new Set(prev);
            next.delete(update.symbol!);
            return next;
          });
        }, 800);
      }
    }
  }, [priceUpdate.latest]);

  // Call handlePriceUpdate when priceUpdate.latest changes
  useEffect(() => {
    handlePriceUpdate();
  }, [priceUpdate.latest, handlePriceUpdate]);

  // Update last updated timestamp whenever priceUpdate.latest changes
  useEffect(() => {
    if (priceUpdate.latest) {
      setLastUpdated(new Date());
    }
  }, [priceUpdate.latest]);

  // Detect stream errors and set error state
  useEffect(() => {
    if (priceUpdate.latest && priceUpdate.latest === undefined) {
      // Stream error detection: if latest is somehow undefined after event, flag it
      setStreamError(null);
    }
  }, [priceUpdate]);
  // Listen for ggui:agent-data events for real-time updates
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail && customEvent.detail.type === 'priceUpdate') {
        // Update is already handled by useStream, but we listen to confirm event flow
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  return {
    priceUpdate,
    marketStatus,
    displayStocks,
    highlightedSymbols,
    lastUpdated,
    streamError,
  };
}



export default function Component(props: Props) {
  const state = useComponent(props);

  // Format timestamp for last updated display
  const formatTime = (date: Date) => {
    return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  };

  // Determine status color and text
  const statusInfo = state.marketStatus.latest
    ? { status: state.marketStatus.latest.status || 'unknown', timestamp: state.marketStatus.latest.timestamp }
    : null;

  const statusColor = statusInfo?.status === 'open' ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-warning-500, #f59e0b)';

  return (
    <Stack gap="var(--ggui-spacing-6, 24px)" direction="vertical" align="stretch">
      {/* Header with title and last updated timestamp */}
      <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius="var(--ggui-shape-radius-md, 8px)">
        <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-4, 16px)">
          <Stack direction="vertical" gap="var(--ggui-spacing-1, 4px)">
            <Heading level={1} color="var(--ggui-color-primary-900, #0c4a6e)">Market Watch</Heading>
          </Stack>
          <Stack direction="vertical" align="end" gap="var(--ggui-spacing-1, 4px)">
            <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Last Updated</Text>
            <Text variant="body" color="var(--ggui-color-primary-900, #0c4a6e)" weight="semibold">{formatTime(state.lastUpdated)}</Text>
          </Stack>
        </Stack>
      </Box>

      {/* Error State */}
      {state.streamError && (
        <Alert variant="error" title="Stream Error" closable onClose={() => setStreamError(null)}>
          {state.streamError}
        </Alert>
      )}

      {/* Loading State */}
      {props.stocks && props.stocks.length === 0 && state.displayStocks.length === 0 ? (
        <Box padding="var(--ggui-spacing-6, 24px)" background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-lg, 12px)" style={{ textAlign: 'center' }}>
          <Stack direction="vertical" gap="var(--ggui-spacing-4, 16px)" align="center" justify="center">
            <Spinner size={32} color="var(--ggui-color-primary-600, #0284c7)" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Loading stock data...</Text>
          </Stack>
        </Box>
      ) : state.displayStocks.length === 0 ? (
        <Box padding="var(--ggui-spacing-6, 24px)" background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-lg, 12px)" style={{ textAlign: 'center' }}>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">No stocks found. Add stocks to get started.</Text>
        </Box>
      ) : (
        <CardGrid columns={{ sm: 1, md: 3 }} gap={16}>
           {(state.displayStocks || []).map((stock) => {
            const isHighlighted = state.highlightedSymbols.has(stock.symbol || '');
            const isPositive = (stock.changePercent ?? 0) >= 0;
            const changeColor = isPositive ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-error-500, #ef4444)';
            const arrowIcon = isPositive ? '▲' : '▼';

            return (
              <Card
                key={stock.symbol}
                padding="var(--ggui-spacing-4, 16px)"
                shadow="md"
                border={true}
                radius="lg"
                style={{
                  borderColor: isHighlighted ? changeColor : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                  animation: isHighlighted ? 'pulse 800ms ease-in-out' : 'none',
                  transition: 'border-color 200ms ease-in-out, background-color 200ms ease-in-out',
                  backgroundColor: isHighlighted ? 'rgba(34, 197, 94, 0.05)' : 'var(--ggui-color-surface)',
                }}
              >
                <Stack direction="vertical" gap="var(--ggui-spacing-2, 8px)">
                  {/* Ticker Symbol - Large and Bold */}
                  <Text variant="overline" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {stock.symbol || 'N/A'}
                  </Text>

                  {/* Company Name */}
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {stock.name || 'Unknown Company'}
                  </Text>

                  {/* Current Price - Formatted with 2 decimals */}
                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)" size="xl">
                    ${(stock.price ?? 0).toFixed(2)}
                  </Text>

                  {/* Divider */}
                  <Divider orientation="horizontal" margin="var(--ggui-spacing-2, 8px)" color="var(--ggui-color-outlineVariant, #e4e4e7)" />

                  {/* Change Amount and Percentage with Arrow */}
                  <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                     <Text variant="label" color={changeColor} weight="semibold">
                       {arrowIcon}
                     </Text>
                     <Text variant="label" color={changeColor} weight="semibold">
                       {isPositive ? '+' : ''}{(stock.change ?? 0).toFixed(2)}
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      )}

      {/* Market Status Footer */}
      {statusInfo && (
        <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)">
          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
            <Box
              style={{
                width: '8px',
                height: '8px',
                borderRadius: '50%',
                backgroundColor: statusColor,
              }}
            />
            <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" weight="medium">
              Market Status: <strong>{(statusInfo.status || 'unknown').charAt(0).toUpperCase() + (statusInfo.status || 'unknown').slice(1)}</strong>
            </Text>
          </Stack>
        </Box>
      )}

      {/* CSS for pulse animation */}
      <style>{`
        @keyframes pulse {
          0%, 100% {
            opacity: 1;
            box-shadow: 0 0 0 0 rgba(34, 197, 94, 0.4);
          }
          50% {
            opacity: 0.85;
            box-shadow: 0 0 12px 4px rgba(34, 197, 94, 0.2);
          }
        }
      `}</style>
    </Stack>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // Step state
  const [currentStep, setCurrentStep] = useState(1);

  // Form state — Step 1: Profile Setup
  const [name, setName] = useState(props.initialProfile.name || '');
  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [selectedAvatar, setSelectedAvatar] = useState(props.initialProfile.avatar || props.avatarOptions[0] || '');

  // Form state — Step 2: Preferences
  const [role, setRole] = useState(props.initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme || 'light');

  // Validation
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isValidEmail = emailRegex.test(email);
  const isStep1Valid = name.trim().length > 0 && email.trim().length > 0 && isValidEmail;
  const isStep2Valid = role.trim().length > 0;

  const handleNext = useCallback(() => {
    if (currentStep === 1 && !isStep1Valid) return;
    if (currentStep === 2 && !isStep2Valid) return;
    setCurrentStep(currentStep + 1);
  }, [currentStep, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    setCurrentStep(Math.max(1, currentStep - 1));
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    if (!isStep1Valid || !isStep2Valid) return;
    complete({
      name,
      email,
      avatar: selectedAvatar,
      role,
      emailNotifications,
      theme,
    });
  }, [name, email, selectedAvatar, role, emailNotifications, theme, isStep1Valid, isStep2Valid, complete]);

  return {
    currentStep,
    name,
    setName,
    email,
    setEmail,
    selectedAvatar,
    setSelectedAvatar,
    role,
    setRole,
    emailNotifications,
    setEmailNotifications,
    theme,
    setTheme,
    isStep1Valid,
    isStep2Valid,
    handleNext,
    handleBack,
    handleComplete,
    emailRegex,
  };
}

function Component(props: Props) {
  const state = useComponent(props);

  const roleOptions = props.roleOptions.map((role) => ({
    value: role,
    label: role.charAt(0).toUpperCase() + role.slice(1),
  }));

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24} align="center">
        {/* Step Indicator */}
        <Stack gap={8} align="stretch">
          <Text variant="label" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)" >
            Step {state.currentStep} of 3
          </Text>
          <Box
            background="var(--ggui-color-outlineVariant, #e4e4e7)"
            borderRadius="var(--ggui-shape-radius-sm, 4px)"
            padding={2}
          >
            <Box
              background="var(--ggui-color-primary-600, #0284c7)"
              borderRadius="var(--ggui-shape-radius-sm, 4px)"
              style={{
                height: 6,
                width: `${(state.currentStep / 3) * 100}%`,
                transition: 'width 300ms ease-in-out',
              }}
            />
          </Box>
        </Stack>

        {/* Step 1: Profile Setup */}
        {state.currentStep === 1 && (
          <Card shadow="md" padding={32} radius="lg" style={{ width: '100%', maxWidth: '500px' }}>
            <Stack gap={24}>
              <Stack gap={8}>
                <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Let's start by setting up your profile information.
                </Text>
              </Stack>

              <Stack gap={16}>
                <Input
                  label="Name"
                  placeholder="John Doe"
                  value={state.name}
                  onChange={state.setName}
                  required
                  error={state.name.trim() === '' && state.name !== '' ? 'Name is required' : ''}
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="you@example.com"
                  value={state.email}
                  onChange={state.setEmail}
                  required
                   error={state.email.trim() === '' ? 'Email is required' : !state.emailRegex.test(state.email) && state.email.length > 0 ? 'Please enter a valid email' : ''}

              <Stack gap={12}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Avatar (required)
                </Text>
                <Stack direction="horizontal" gap={8} justify="center" wrap>
                  {props.avatarOptions.map((emoji) => (
                    <Box
                      key={emoji}
                      as={Clickable}
                      onClick={() => state.setSelectedAvatar(emoji)}
                      padding={12}
                      borderRadius="var(--ggui-shape-radius-md, 8px)"
                      background={
                        state.selectedAvatar === emoji
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      }
                      style={{
                        cursor: 'pointer',
                        fontSize: '32px',
                        transition: 'all 200ms ease-in-out',
                      }}
                      hoverStyle={{
                        background:
                          state.selectedAvatar === emoji
                            ? 'var(--ggui-color-primary-700, #0369a1)'
                            : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                      }}
                    >
                      {emoji}
                    </Box>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {state.currentStep === 2 && (
          <Card shadow="md" padding={32} radius="lg" style={{ width: '100%', maxWidth: '500px' }}>
            <Stack gap={24}>
              <Stack gap={8}>
                <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Customize your experience with these settings.
                </Text>
              </Stack>

              <Stack gap={16}>
                <Select
                  label="Role"
                  value={state.role}
                  onChange={state.setRole}
                  options={roleOptions}
                  placeholder="Select your role"
                  required
                   error={state.role.trim() === '' && state.role !== '' ? 'Role is required' : ''}

                <Checkbox
                  label="Enable email notifications"
                  description="Receive updates and notifications via email"
                  checked={state.emailNotifications}
                  onChange={state.setEmailNotifications}
                />
              </Stack>

              <Stack gap={12}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Theme Preference
                </Text>
                <RadioGroup
                  value={state.theme}
                  onChange={state.setTheme}
                  options={[
                    { value: 'light', label: 'Light Mode' },
                    { value: 'dark', label: 'Dark Mode' },
                  ]}
                  direction="horizontal"
                />
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {state.currentStep === 3 && (
          <Card shadow="md" padding={32} radius="lg" style={{ width: '100%', maxWidth: '500px' }}>
            <Stack gap={24}>
              <Stack gap={8}>
                <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                  Review Your Setup
                </Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Please review your information before completing setup.
                </Text>
              </Stack>

              <Stack gap={16} style={{ backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)' }}>
                <Stack gap={12}>
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ minWidth: '100px' }}>
                      Avatar:
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" style={{ fontSize: '24px' }}>
                      {state.selectedAvatar}
                    </Text>
                  </Stack>
                  <Divider margin={0} />
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ minWidth: '100px' }}>
                      Name:
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" >
                      {state.name}
                    </Text>
                  </Stack>
                  <Divider margin={0} />
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ minWidth: '100px' }}>
                      Email:
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" >
                      {state.email}
                    </Text>
                  </Stack>
                  <Divider margin={0} />
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ minWidth: '100px' }}>
                      Role:
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" >
                      {state.role.charAt(0).toUpperCase() + state.role.slice(1)}
                    </Text>
                  </Stack>
                  <Divider margin={0} />
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ minWidth: '100px' }}>
                      Notifications:
                    </Text>
                    <Badge variant={state.emailNotifications ? 'success' : 'default'}>
                      {state.emailNotifications ? 'Enabled' : 'Disabled'}
                    </Badge>
                  </Stack>
                  <Divider margin={0} />
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ minWidth: '100px' }}>
                      Theme:
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" >
                      {state.theme.charAt(0).toUpperCase() + state.theme.slice(1)}
                    </Text>
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Stack direction="horizontal" gap={12} justify="center" style={{ width: '100%', maxWidth: '500px' }}>
          <Button
            variant="ghost"
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
          >
            Go Back
          </Button>
          {state.currentStep < 3 && (
            <Button
              variant="primary"
              onClick={state.handleNext}
              disabled={state.currentStep === 1 ? !state.isStep1Valid : !state.isStep2Valid}
              fullWidth
            >
              Next
            </Button>
          )}
          {state.currentStep === 3 && (
            <Button
              variant="primary"
              onClick={state.handleComplete}
              disabled={!state.isStep1Valid || !state.isStep2Valid}
              fullWidth
            >
              Complete Setup
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

export default Component;
